pure fn char_frequencies(s: Text) -> [Text] {
    chars = split(s, "")
    freq_chars = []
    freq_counts = []
    for c in chars {
        idx = -1
        for i in range(0, length(freq_chars)) {
            if get(freq_chars, i) == c { idx = i }
        }
        if idx == -1 {
            freq_chars = append(freq_chars, c)
            freq_counts = append(freq_counts, 1)
        } else {
            freq_counts = append(freq_counts, get(freq_counts, idx) + 1)
            # Remove old count at idx
            temp = []
            for j in range(0, length(freq_counts) - 1) {
                if j != idx { temp = append(temp, get(freq_counts, j)) }
            }
            freq_counts = append(temp, get(freq_counts, length(freq_counts) - 1))
        }
    }
    result = []
    for k in range(0, length(freq_chars)) {
        result = append(result, join([get(freq_chars, k), ": ", to_text(get(freq_counts, k))], ""))
    }
    return result
}
entry main(x: Text) {
    return join(char_frequencies("mississippi"), ", ")
}

