pure fn parse_ymd(date: Text) -> [Number] {
    nums = split(date, "-")
    if length(nums) == 3 {
        y = to_number(get(nums, 0))
        m = to_number(get(nums, 1))
        d = to_number(get(nums, 2))
        return [y, m, d]
    }
    return [0,0,0]
}
pure fn days_in_month(year: Number, month: Number) -> Number {
    if month in [1,3,5,7,8,10,12] { return 31 }
    if month in [4,6,9,11] { return 30 }
    if month == 2 {
        if (year % 4 == 0 and year % 100 != 0) or (year % 400 == 0) { return 29 }
        return 28
    }
    return 0
}
pure fn days_since_epoch(y: Number, m: Number, d: Number) -> Number {
    days = 0
    for year in range(1970, y) {
        days = days + 365
        if (year % 4 == 0 and year % 100 != 0) or (year % 400 == 0) { days = days + 1 }
    }
    for month in range(1, m) {
        days = days + days_in_month(y, month)
    }
    days = days + d
    return days
}
pure fn days_between(date1: Text, date2: Text) -> Number {
    ymd1 = parse_ymd(date1)
    ymd2 = parse_ymd(date2)
    d1 = days_since_epoch(get(ymd1,0), get(ymd1,1), get(ymd1,2))
    d2 = days_since_epoch(get(ymd2,0), get(ymd2,1), get(ymd2,2))
    return abs(d2 - d1)
}
