pure fn variance(nums: [Number]) -> Number {
    m = mean(nums)
    sum_sq = 0
    for n in nums { sum_sq = sum_sq + (n - m) * (n - m) }
    return sum_sq / length(nums)
}
pure fn stddev(nums: [Number]) -> Number {
