pure fn compound_interest(principal: Number, rate: Number, years: Number) -> Number {
    return principal * pow(1 + rate / 100, years)
}
intent explain_to_teenager(amount: Number, principal: Number, rate: Number, years: Number) -> Text {
    goal: explain_compound_interest_result_in_simple_terms
}
entry main(x: Text) {
    principal = 1000
    rate = 5
    years = 3
    amount = compound_interest(principal, rate, years)
    return explain_to_teenager(amount, principal, rate, years)
}

pure fn line_count(s: Text) -> Number {
    return length(split(s, ". "))
}
pure fn word_count(s: Text) -> Number {
    ws = split(s, " ")
    count = 0
    for w in ws {
        if trim(w) != "" { count = count + 1 }
    }
    return count
}
pure fn char_count(s: Text) -> Number {
    return length(s)
}
intent rate_conciseness(s: Text) -> Text {
    goal: rate as concise or verbose
}
entry main(x: Text) {
    text = "The sun was setting. Birds flew home. Silence fell."
    lines = line_count(text)
    words = word_count(text)
    chars = char_count(text)
    rating = rate_conciseness(text)
    return join([
        "Lines: ", to_text(lines), ", Words: ", to_text(words), ", Characters: ", to_text(chars), ", Rating: ", rating
    ], "")
}

pure fn parse_city_latitudes(s: Text) -> [[Text]] {
    pairs = split(s, ",")
    result = []
    for p in pairs {
        parts = split(p, ":")
        if length(parts) == 2 {
            city = get(parts, 0)
            lat = get(parts, 1)
            result = append(result, [city, lat])
        }
    }
    return result
}

pure fn sort_by_latitude(pairs: [[Text]]) -> [[Text]] {
    n = length(pairs)
    for i in range(0, n) {
        for j in range(i + 1, n) {
            lati = to_number(get(get(pairs, i), 1))
            latj = to_number(get(get(pairs, j), 1))
            if lati > latj {
                tmp = get(pairs, i)
                pairs = append(append([], get(pairs, 0)), get(pairs, 1)) // dummy to force copy
                pairs = append(pairs, get(pairs, j))
                pairs = append(pairs, tmp)
            }
        }
    }
    return pairs
}

intent describe_pattern(sorted_pairs: [[Text]]) -> Text {
    goal: describe the geographic pattern in the sorted city-latitude pairs
}

entry main(x: Text) {
    pairs = parse_city_latitudes(x)
    sorted_pairs = sort_by_latitude(pairs)
    return describe_pattern(sorted_pairs)
}

pure fn fibonacci(n: Number) -> [Number] {
    seq = [0, 1]
    for i in range(2, n) {
        next = get(seq, i - 1) + get(seq, i - 2)
        seq = append(seq, next)
    }
    return seq
}
intent explain_golden_ratio(seq: [Number]) -> Text {
    goal: explain_why_golden_ratio_appears_in_fibonacci_sequence
}
entry main(x: Text) {
    fib = fibonacci(8)
    explanation = explain_golden_ratio(fib)
    return join([join(map(fib, "to_text"), ", "), "\n", explanation], "")
}

pure fn remove_stop_words(text: Text) -> Text {
    stop_words = ["the", "a", "an", "is", "in", "on", "at", "to"]
    words = split(trim(lower(text)), " ")
    filtered = []
    for w in words {
        if w not in stop_words { filtered = append(filtered, w) }
    }
    return join(filtered, " ")
}
import summarize from "stdlib/language"
entry main(x: Text) {
    filtered = remove_stop_words("the cat is on the mat in the room")
    return summarize(filtered, 20)
}
